import CryptoJS from 'crypto-js';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { ENCRYPTION_KEY } from '../config/encryption';

class EncryptionService {
  constructor() {
    this.key = ENCRYPTION_KEY;
  }

  encrypt(data) {
    try {
      const stringData = typeof data === 'string' ? data : JSON.stringify(data);
      const encrypted = CryptoJS.AES.encrypt(stringData, this.key).toString();
      return encrypted;
    } catch (error) {
      console.error('Encryption error:', error);
      throw new Error('Failed to encrypt data');
    }
  }

  decrypt(encryptedData) {
    try {
      const decrypted = CryptoJS.AES.decrypt(encryptedData, this.key);
      const decryptedString = decrypted.toString(CryptoJS.enc.Utf8);
      
      if (!decryptedString) {
        throw new Error('Decryption resulted in empty string');
      }

      try {
        return JSON.parse(decryptedString);
      } catch (e) {
        return decryptedString;
      }
    } catch (error) {
      console.error('Decryption error:', error);
      throw new Error('Failed to decrypt data');
    }
  }

  async setSecureItem(key, value) {
    try {
      const encryptedValue = this.encrypt(value);
      await AsyncStorage.setItem(key, encryptedValue);
      return true;
    } catch (error) {
      console.error('Error storing secure item:', error);
      throw error;
    }
  }

  async getSecureItem(key) {
    try {
      const encryptedValue = await AsyncStorage.getItem(key);
      if (encryptedValue === null) {
        return null;
      }
      return this.decrypt(encryptedValue);
    } catch (error) {
      console.error('Error retrieving secure item:', error);
      throw error;
    }
  }

  async removeSecureItem(key) {
    try {
      await AsyncStorage.removeItem(key);
      return true;
    } catch (error) {
      console.error('Error removing secure item:', error);
      throw error;
    }
  }

  async clearAllSecureData() {
    try {
      await AsyncStorage.clear();
      return true;
    } catch (error) {
      console.error('Error clearing secure data:', error);
      throw error;
    }
  }
}

export default new EncryptionService();

