// hooks/useSecureStorage.js
import { useState, useEffect } from 'react';
import SecureStorageManager from '../services/secureStorageManager';

export const useSecureStorage = (key, initialValue = null) => {
  const [value, setValue] = useState(initialValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    loadValue();
  }, [key]);

  const loadValue = async () => {
    try {
      setLoading(true);
      const storedValue = await SecureStorageManager.encryptionService.getSecureItem(key);
      setValue(storedValue || initialValue);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const saveValue = async (newValue) => {
    try {
      await SecureStorageManager.encryptionService.setSecureItem(key, newValue);
      setValue(newValue);
      setError(null);
      return { success: true };
    } catch (err) {
      setError(err.message);
      return { success: false, error: err.message };
    }
  };

  const removeValue = async () => {
    try {
      await SecureStorageManager.encryptionService.removeSecureItem(key);
      setValue(initialValue);
      setError(null);
      return { success: true };
    } catch (err) {
      setError(err.message);
      return { success: false, error: err.message };
    }
  };

  return {
    value,
    loading,
    error,
    setValue: saveValue,
    removeValue,
    reload: loadValue
  };
};

// Example usage component
import React, { useState, useEffect } from 'react';
import { View, Text, TextInput, Button, StyleSheet, ScrollView } from 'react-native';
import SecureStorageManager from './services/secureStorageManager';

const App = () => {
  const [userProfile, setUserProfile] = useState(null);
  const [authToken, setAuthToken] = useState(null);
  const [paymentInfo, setPaymentInfo] = useState(null);

  const handleSaveUserProfile = async () => {
    const profile = {
      id: '12345',
      name: 'John Doe',
      email: 'john.doe@example.com',
      phone: '+1234567890',
      address: '123 Main St, City, Country'
    };

    const result = await SecureStorageManager.userProfile.save(profile);
    if (result.success) {
      console.log('User profile saved successfully');
      loadUserProfile();
    }
  };

  const loadUserProfile = async () => {
    const result = await SecureStorageManager.userProfile.get();
    if (result.success) {
      setUserProfile(result.data);
    }
  };

  const handleSavePaymentInfo = async () => {
    const payment = {
      cardNumber: '4111111111111111',
      cvv: '123',
      expiryDate: '12/25',
      cardHolderName: 'John Doe',
      billingAddress: '123 Main St'
    };

    const result = await SecureStorageManager.payment.save(payment);
    if (result.success) {
      console.log('Payment info saved successfully');
      loadPaymentInfo();
    }
  };

  const loadPaymentInfo = async () => {
    const result = await SecureStorageManager.payment.get();
    if (result.success) {
      setPaymentInfo(result.data);
    }
  };

  const handleSaveAuthData = async () => {
    const authData = {
      token: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...',
      refreshToken: 'refresh_token_here',
      credentials: {
        username: 'johndoe',
        userId: '12345'
      }
    };

    const result = await SecureStorageManager.auth.saveAll(authData);
    if (result.success) {
      console.log('Auth data saved successfully');
      loadAuthToken();
    }
  };

  const loadAuthToken = async () => {
    const result = await SecureStorageManager.auth.getToken();
    if (result.success) {
      setAuthToken(result.data);
    }
  };

  const handleClearAll = async () => {
    const result = await SecureStorageManager.clearAllData();
    if (result.success) {
      console.log('All data cleared');
      setUserProfile(null);
      setAuthToken(null);
      setPaymentInfo(null);
    }
  };

  useEffect(() => {
    loadUserProfile();
    loadAuthToken();
    loadPaymentInfo();
  }, []);

  return (
    <ScrollView style={styles.container}>
      <View style={styles.section}>
        <Text style={styles.title}>Secure Storage Demo</Text>
        
        <View style={styles.buttonGroup}>
          <Button title="Save User Profile" onPress={handleSaveUserProfile} />
          <Button title="Save Payment Info" onPress={handleSavePaymentInfo} />
          <Button title="Save Auth Data" onPress={handleSaveAuthData} />
          <Button title="Clear All Data" onPress={handleClearAll} color="red" />
        </View>

        {userProfile && (
          <View style={styles.dataSection}>
            <Text style={styles.sectionTitle}>User Profile:</Text>
            <Text>{JSON.stringify(userProfile, null, 2)}</Text>
          </View>
        )}

        {authToken && (
          <View style={styles.dataSection}>
            <Text style={styles.sectionTitle}>Auth Token:</Text>
            <Text numberOfLines={1}>{authToken}</Text>
          </View>
        )}

        {paymentInfo && (
          <View style={styles.dataSection}>
            <Text style={styles.sectionTitle}>Payment Info:</Text>
            <Text>{JSON.stringify(paymentInfo, null, 2)}</Text>
          </View>
        )}
      </View>
    </ScrollView>
  );
};

